#ifndef MOVING_AVERAGE_H
#define MOVING_AVERAGE_H
#include <Arduino.h>

class MovingAverage {
public:
    MovingAverage(int windowSize = 5);
    float update(float newValue);
    float getValue() const;
    void reset();
private:
    float* _buffer;
    int _windowSize;
    int _index;
    int _count;
    float _sum;
};

#endif

firmware_template.source:
#include "moving_average.h"

MovingAverage::MovingAverage(int windowSize)
    : _windowSize(windowSize), _index(0), _count(0), _sum(0.0f) {
    _buffer = new float[windowSize];
    for (int i = 0; i < windowSize; i++) _buffer[i] = 0.0f;
}

float MovingAverage::update(float newValue) {
    if (_count >= _windowSize) {
        _sum -= _buffer[_index];
    } else {
        _count++;
    }
    _buffer[_index] = newValue;
    _sum += newValue;
    _index = (_index + 1) % _windowSize;
    return getValue();
}

float MovingAverage::getValue() const {
    return _count > 0 ? _sum / _count : 0.0f;
}

void MovingAverage::reset() {
    _index = 0; _count = 0; _sum = 0.0f;
    for (int i = 0; i < _windowSize; i++) _buffer[i] = 0.0f;
}
